ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?released_seasons ?planned_seasons WHERE {
  ?tv_shows a :TV_Shows .
  ?tv_shows p:Released_Seasons ?released_seasons .
  ?tv_shows p:Planned_Seasons ?planned_seasons .
  ?tv_shows p:Series ?series_f .
  FILTER(STR(?series_f) = STR("Mystery Sci-Fi"))
} }
  component: { SELECT ?planned_seasons WHERE {
  ?tv_shows a :TV_Shows .
  ?tv_shows p:Planned_Seasons ?planned_seasons .
  ?tv_shows p:Series ?series_f .
  FILTER(STR(?series_f) = STR("Mystery Sci-Fi"))
} }
  component_2: { SELECT ?released_seasons WHERE {
  ?tv_shows a :TV_Shows .
  ?tv_shows p:Released_Seasons ?released_seasons .
  ?tv_shows p:Series ?series_f .
  FILTER(STR(?series_f) = STR("Mystery Sci-Fi"))
} }
}
